def to_twos_complement(n, bits):
    if n >= 0:
        return format(n, f'0{bits}b')
    else:
        # Compute two's complement: 2^n + n
        return format((1 << bits) + n, f'0{bits}b')

def from_twos_complement(binary_str):
    bits = len(binary_str)
    value = int(binary_str, 2)
    # If negative (MSB is 1), subtract 2^bits
    if value >= (1 << (bits - 1)):
        value -= (1 << bits)
    return value

# Examples
print(to_twos_complement(-5, 8))   # Output: 11111011
print(from_twos_complement('11111011'))  # Output: -5
print(to_twos_complement(127, 8))  # Output: 01111111

#include <stdio.h>
#include <stdbool.h>

bool detect_overflow(int a, int b, int result) {
    // Check if both operands have same sign
    bool a_negative = a < 0;
    bool b_negative = b < 0;
    bool result_negative = result < 0;

    // Overflow when signs are same but result sign differs
    return (a_negative == b_negative) && (result_negative != a_negative);
}

int add_with_overflow_check(int a, int b) {
    int result = a + b;

    if (detect_overflow(a, b, result)) {
        printf("Warning: Overflow occurred!\\n");
    }
    return result;
}

int main() {
    // Test cases
    printf("%d + %d = %d\\n", 45, 78, add_with_overflow_check(45, 78));   // No overflow
    printf("%d + %d = %d\\n", -45, -78, add_with_overflow_check(-45, -78)); // No overflow
    printf("%d + %d = %d\\n", 100, 60, add_with_overflow_check(100, 60));  // Overflow!
    return 0;
}

def convert_number(value, from_base=10, to_base=2):
    """Convert between decimal, binary, octal, hex"""
    # First convert to decimal
    if from_base == 10:
        decimal_val = int(value)
    elif from_base == 2:
        decimal_val = int(value, 2)
    elif from_base == 8:
        decimal_val = int(value, 8)
    elif from_base == 16:
        decimal_val = int(value, 16)

    # Convert to target base
    if to_base == 10:
        return str(decimal_val)
    elif to_base == 2:
        return bin(decimal_val)[2:]  # Remove '0b'
    elif to_base == 8:
        return oct(decimal_val)[2:]  # Remove '0o'
    elif to_base == 16:
        return hex(decimal_val)[2:].upper()  # Remove '0x'

# Examples
print(convert_number(93, 10, 2))     # Binary: 1011101
print(convert_number('1011101', 2, 10))  # Decimal: 93
print(convert_number('5D', 16, 2))    # Binary: 1011101 (93)
print(convert_number(255, 10, 16))   # Hex: FF
print(convert_number(93, 10, 8))      # Octal: 135

public class SignExtension {
    public static String signExtend(String binary, int newBits) {
        if (binary.length() >= newBits) {
            return binary;  // No extension needed
        }

        char signBit = binary.charAt(0);  // Get the sign bit
        int padding = newBits - binary.length();

        // Create padding with the sign bit
        StringBuilder paddingStr = new StringBuilder();
        for (int i = 0; i < padding; i++) {
            paddingStr.append(signBit);
        }

        return paddingStr.toString() + binary;
    }

    public static int interpretTwosComplement(String binary) {
        int value = Integer.parseInt(binary, 2);
        int bits = binary.length();

        // If negative (MSB is 1), apply sign extension to 32 bits
        if (value >= (1 << (bits - 1))) {
            value = value - (1 << bits);
        }
        return value;
    }

    public static void main(String[] args) {
        // Sign extend 8-bit to 16-bit
        String pos8bit = "00001101";  // +13
        String neg8bit = "11111011";  // -5

        System.out.println("Sign Extension Examples:");
        System.out.println("+13: " + signExtend(pos8bit, 16) + " (16-bit)");
        System.out.println("-5:  " + signExtend(neg8bit, 16) + " (16-bit)");

        // Interpret values
        System.out.println("\nInterpretation:");
        System.out.println("00001101 (8-bit) = " + interpretTwosComplement(pos8bit));
        System.out.println("11111011 (8-bit) = " + interpretTwosComplement(neg8bit));
        System.out.println("0000000011111011 (16-bit) = " + interpretTwosComplement(signExtend(neg8bit, 16)));
    }
}
